module top_module(
    Y,
    A
);output Y;
    input  [11:0] A;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire [11:0] cleared_bits;

    // Generate inverted inputs
    assign cleared_bits = ~A;

    // Generate output
    assign Y = cleared_bits[11] & cleared_bits[10] & cleared_bits[9] & cleared_bits[8] & cleared_bits[7] & cleared_bits[6] & cleared_bits[5] & cleared_bits[4] & cleared_bits[3] & cleared_bits[2] & cleared_bits[1] & cleared_bits[0];

endmodule
